#include <vector>

/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_durbin(int n,
                   std::vector<double>& r,
                   std::vector<double>& y) {

    std::vector<double> z(n, 0.0);     /* scratch space */
    y[0] = -r[0];
    double beta  = 1.0;
    double alpha = -r[0];

    for (int k = 1; k < n; ++k) {
        beta = (1.0 - alpha * alpha) * beta;

        /* compute sum of products r[k-i-1] * y[i] */
        double sum = 0.0;
        for (int i = 0; i < k; ++i)
            sum += r[k - i - 1] * y[i];

        alpha = -(r[k] + sum) / beta;

        /* update y using auxiliary buffer z */
        for (int i = 0; i < k; ++i)
            z[i] = y[i] + alpha * y[k - i - 1];

        for (int i = 0; i < k; ++i)
            y[i] = z[i];

        y[k] = alpha;
    }
}
