/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_cholesky(int n, std::vector<std::vector<double>>& A) {
    // Parallelise only the outer loop – inner loops have data dependencies
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        // Non‑diagonal entries
        for (int j = 0; j < i; ++j) {
            double sum = 0.0;
            for (int k = 0; k < j; ++k) {
                sum += A[i][k] * A[j][k];
            }
            A[i][j] = (A[i][j] - sum) / A[j][j];
        }

        // Diagonal entry
        double sum = 0.0;
        for (int k = 0; k < i; ++k) {
            sum += A[i][k] * A[i][k];
        }
        A[i][i] -= sum;
        A[i][i] = std::sqrt(A[i][i]);
    }
}
