void kernel_floyd_warshall(int n, std::vector<std::vector<int>>& path) {
    // Parallelise over the outer loop (k).  Each thread works on a distinct
    // set of rows so no data races occur.
    for (int k = 0; k < n; ++k) {
        #pragma omp parallel for schedule(static)
        for (int i = 0; i < n; ++i) {
            int ik = path[i][k];                // cache read
            for (int j = 0; j < n; ++j) {
                int newCost = ik + path[k][j];
                if (newCost < path[i][j]) {
                    path[i][j] = newCost;      // write
                }
            }
        }
    }
