void kernel_trisolv(int n,
                    std::vector<std::vector<double>>& L,
                    std::vector<double>& x,
                    std::vector<double>& b) {
    // Forward substitution L x = b (L is lower‑triangular).
    for (int i = 0; i < n; ++i) {
