    double* x1_ptr = x1.data();
    double* x2_ptr = x2.data();
    const double* y1_ptr = y_1.data();
    const double* y2_ptr = y_2.data();
    const double* A_ptr = &A[0][0];          // assumes all rows have length n

    const int stride = n;

    // First loop: x1 += A * y1
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        const double* a_row = A_ptr + i * stride;
        for (int j = 0; j < n; ++j) {
            sum += a_row[j] * y1_ptr[j];
        }
        x1_ptr[i] += sum;
    }

    // Second loop: x2 += A^T * y2
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        // Access A[j][i] => A_ptr[j*n + i]
        for (int j = 0; j < n; ++j) {
            sum += *(A_ptr + j * stride + i) * y2_ptr[j];
        }
