void kernel_covariance(int m, int n,
                       std::vector<std::vector<double>>& data,
                       std::vector<std::vector<double>>& cov,
                       std::vector<double>& mean) {
    // ------------------------------------------------------------------
    // 1) Compute column means
    // ------------------------------------------------------------------
#pragma omp parallel for
    for (int j = 0; j < m; ++j) {
        double sum = 0.0;
        for (int i = 0; i < n; ++i) {
            sum += data[i][j];
        }
        mean[j] = sum / static_cast<double>(n);
    }

    // ------------------------------------------------------------------
    // 2) Center the data (data[i][j] -= mean[j])
    // ------------------------------------------------------------------
#pragma omp parallel for
    for (int i = 0; i < n; ++i) {
        double* row = data[i].data();
        const double* mptr = mean.data();
        for (int j = 0; j < m; ++j) {
            row[j] -= mptr[j];
        }
    }

    // ------------------------------------------------------------------
    // 3) Compute upper‑triangular part of covariance matrix
    //    and mirror it to the lower part
    // ------------------------------------------------------------------
#pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double* cov_i = cov[i].data();
        for (int j = i; j < m; ++j) {
            double sum = 0.0;
            for (int k = 0; k < n; ++k) {
                sum += data[k][i] * data[k][j];
            }
            double val = sum / static_cast<double>(n - 1);
            cov_i[j] = val;
            cov[j][i] = val;  // symmetric
        }
    }
}
