/* Main computational kernel. The whole function will be timed,
   including the call and return.  The signature must stay the same.
   The implementation has been rewritten for speed: 
   - A and B are accessed as contiguous blocks (row major).
   - An OpenMP parallel loop over the first dimension is used.
   - The inner loops are reordered for better cache locality.
   */
void kernel_trmm(int m, int n,
                 double alpha,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B) {

    // Row‑major address helpers
    const std::size_t A_stride = m;          // columns in A    M x M
    const std::size_t B_stride = n;          // columns in B    M x N

    double const *Adata = &A[0][0];
    double *Bdata = &B[0][0];

    // Parallelise the outermost loop to keep the inner loop very
    // cache‑friendly.  The scheduler is static to avoid overhead.
    #pragma omp parallel for schedule(static) num_threads(8)
    for (int i = 0; i < m; ++i) {
        const double *Ai = Adata + i;            // pointer to column i of A (because we need A[k][i])
        double *Bi = Bdata + i * B_stride;       // pointer to row i of B

        for (int j = 0; j < n; ++j) {
            double sum = Bi[j];                  // start with current B[i][j]
            // Sum over k from i+1 .. m-1
            for (int k = i + 1; k < m; ++k) {
                // A[k][i] is stored at Adata + k* A_stride + i
                sum += Adata + k * A_stride + i )[0] * Bdata + k * B_stride + j [0];
            }
            Bi[j] = alpha * sum;                 // final scaling
        }
    }
}
