#include <vector>
#include <omp.h>

/*  Optimized SYRK kernel:
 *      C := alpha * A * A^T + beta * C
 *  A is n × m, C is n × n (lower triangular is used).
 *  The function signature is kept identical to the harness.
 */
void kernel_syrk(int n, int m,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& C,
                 std::vector<std::vector<double>>& A) {

    /* 1. Flatten the 2‑D vectors to 1‑D for better cache line layout.   */
    const double *a = new double[n * m];
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < m; ++j)
            a[i * m + j] = A[i][j];

    double *c = new double[n * n];
    for (int i = 0; i < n; ++i)
        for (int j = 0; j <= i; ++j)
            c[i * n + j] = C[i][j];

    /* 2. Blocked, parallel implementation.   */
    const int B = 64;                    // block size (tuned for L1 cache)
    int nb = (n + B - 1) / B;            // number of blocks

    #pragma omp parallel for schedule(dynamic)
    for (int bi = 0; bi < nb; ++bi) {
        int i0 = bi * B;
        int i1 = std::min(i0 + B, n);
        for (int bj = 0; bj <= bi; ++bj) { // lower triangular only
            int j0 = bj * B;
            int j1 = std::min(j0 + B, n);
            for (int i = i0; i < i1; ++i) {
                for (int j = j0; j <= std::min(i, j1 - 1); ++j) {
                    double sum = c[i * n + j] * beta;
                    for (int k = 0; k < m; ++k)
                        sum += alpha * a[i * m + k] * a[j * m + k];
                    c[i * n + j] = sum;
                }
            }
        }
    }

    /* 3. Copy results back into the original vector of vectors.   */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j <= i; ++j)
            C[i][j] = c[i * n + j];

    delete[] a;
    delete[] c;
}
