/* Optimised kernel: same interface, same semantic result.
   Uses flat arrays for contiguous memory, OpenMP parallelisation,
   elimination of bounds checks and redundant indirections. */
void kernel_doitgen(int nr, int nq, int np,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<double>>& C4,
                    std::vector<double>& sum)
{
    // Flatten A into a single array for better cache utilisation
    // A_flat[r * nq + q][s]  -> A_flat[(r*nq+q)*np + s]
    std::vector<double> A_flat(static_cast<std::size_t>(nr)*nq*np);
    for (int r = 0; r < nr; ++r)
        for (int q = 0; q < nq; ++q)
            for (int s = 0; s < np; ++s)
                A_flat[(r*nq+q)*np + s] = A[r][q][s];

    // References to C4  (no copy)
    double* const* C4_ref = reinterpret_cast<double* const*>(C4.data());

    // Parallelise over (r, q) pairs
    #pragma omp parallel for collapse(2) schedule(static)
    for (int r = 0; r < nr; ++r)
        for (int q = 0; q < nq; ++q)
        {
            double* Arow = &A_flat[(r*nq+q)*np];
            for (int p = 0; p < np; ++p)
            {
                double s_val = 0.0;
                // unroll the inner loop a bit for speed
                int s = 0;
                for (; s + 3 < np; s += 4)
                {
                    s_val += Arow[s]   * C4_ref[s][p];
                    s_val += Arow[s+1] * C4_ref[s+1][p];
                    s_val += Arow[s+2] * C4_ref[s+2][p];
                    s_val += Arow[s+3] * C4_ref[s+3][p];
                }
                for (; s < np; ++s)
                    s_val += Arow[s] * C4_ref[s][p];

                sum[p] = s_val;            // temporary store
                Arow[p] = s_val;            // write back
            }
        }

    // Copy results back into the original A structure
    for (int r = 0; r < nr; ++r)
        for (int q = 0; q < nq; ++q)
            for (int s = 0; s < np; ++s)
                A[r][q][s] = A_flat[(r*nq+q)*np + s];
}
