void kernel_lu(int n, std::vector<std::vector<double>>& A) {
    // Flatten the 2‑D vector for efficient access
    double* a = &A[0][0];
    const std::ptrdiff_t stride = n;

    for (int i = 0; i < n; ++i) {
        /* first part: fill lower triangle (j < i) */
        for (int j = 0; j < i; ++j) {
            double* aik = a + i * stride;      // row i
            double* akk = a + j * stride;      // row j
            double* akj = a + j;               // column j

            // sum over k < j
            for (int k = 0; k < j; ++k)
                aik[j] -= aik[k] * a[k * stride + j];
            aik[j] /= a[j * stride + j];
        }

        /* second part: fill upper triangle including diagonal (j >= i) */
        for (int j = i; j < n; ++j) {
            double* aik = a + i * stride;      // row i
            double* akk = a + j * stride;      // row j

            // sum over k < i
            for (int k = 0; k < i; ++k)
                aik[j] -= aik[k] * a[k * stride + j];
        }
    }
}
