/* Optimised syr2k kernel.
 * Parameters:
 *   n – size of the symmetric matrix C (n x n)
 *   m – number of columns in A and B (n x m)
 *   alpha, beta – scalars used in the computation
 *   C, A, B – square or rectangular matrices stored as
 *             std::vector<std::vector<double>> with contiguous
 *             row‑major storage (each inner vector has the
 *             same size).
 *
 * The function preserves the exact semantics of the original
 * implementation: only the lower triangular part of C is
 * updated, where C[i][j] = beta*C[i][j] +
 *   alpha*(A[j][k]*B[i][k] + B[j][k]*A[i][k]) summed over k.
 */
void kernel_syr2k(int n, int m,
                  double alpha,
                  double beta,
                  std::vector<std::vector<double>>& C,
                  std::vector<std::vector<double>>& A,
                  std::vector<std::vector<double>>& B)
{
    // Alias to the underlying contiguous data
    const double *A_data = &A[0][0];
    const double *B_data = &B[0][0];
          double *C_data = &C[0][0];

    const int lda = n;   // leading dimension of A and B (row length)

    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double *C_row = C_data + i * lda;
        const double *B_row = B_data + i * lda;

        // Scale the lower‑triangular part of this row by beta
        for (int j = 0; j <= i; ++j) {
            C_row[j] *= beta;
        }

        // Accumulate the rank‑2 update
        for (int k = 0; k < m; ++k) {
            double aik = A_data[k * lda + i];   // A[i][k]
            double bkj = B_data[k * lda + i];   // B[i][k]
            double temp1, temp2;
            for (int j = 0; j <= i; ++j) {
                temp1 = A_data[k * lda + j] * bkj * alpha; // A[j][k] * B[i][k] * alpha
                temp2 = B_data[k * lda + j] * aik * alpha; // B[j][k] * A[i][k] * alpha
                C_row[j] += temp1 + temp2;
            }
        }
    }
}
