    double* ex_data = static_cast<double*>(ex.data()->data());
    double* ey_data = static_cast<double*>(ey.data()->data());
    double* hz_data = static_cast<double*>(hz.data()->data());

    const int stride = nx;                // stride between rows in the flattened array
    const int ny_range = ny;
    const int nx_range = nx;

    for (int t = 0; t < tmax; ++t) {
        // ---------- update ey on first column ----------
        #pragma omp parallel for schedule(static)
        for (int j = 0; j < ny_range; ++j) {
            ey_data[j] = _fict_[t];
        }

        // ---------- update ey for i>0 ----------
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < nx_range; ++i) {
            for (int j = 0; j < ny_range; ++j) {
                size_t idx    = i * stride + j;
                size_t idx_pre = (i-1) * stride + j;
                ey_data[idx] -= 0.5 * (hz_data[idx] - hz_data[idx_pre]);
            }
        }

        // ---------- update ex ----------
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < nx_range; ++i) {
            for (int j = 1; j < ny_range; ++j) {
                size_t idx    = i * stride + j;
                size_t idx_pre = i * stride + (j-1);
                ex_data[idx] -= 0.5 * (hz_data[idx] - hz_data[idx_pre]);
            }
        }

        // ---------- update hz ----------
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 0; i < nx_range-1; ++i) {
            for (int j = 0; j < ny_range-1; ++j) {
                size_t idx = i * stride + j;
                size_t idx_ex_plus  = i * stride + (j+1);
                size_t idx_ey_plus  = (i+1) * stride + j;
                hz_data[idx] -= 0.7 * (ex_data[idx_ex_plus] - ex_data[idx]
