#include <vector>
#include <cstdlib>
#include <cstring>
#include <omp.h>

void kernel_gemm(int ni, int nj, int nk,
                 double alpha,
                 double beta,
                 std::vector<std::vector<double>>& A,
                 std::vector<std::vector<double>>& B,
                 std::vector<std::vector<double>>& C)
{
    const int BLOCK_I = 64;   // block size for i
    const int BLOCK_K = 64;   // block size for k
    const int BLOCK_J = 64;   // block size for j

    // Convert input vectors to contiguous 1‑D arrays
    double *a = new double[ni * nk];
    double *b = new double[nk * nj];
    double *c = new double[ni * nj];

    for (int i = 0; i < ni; ++i)
        std::memcpy(a + i * nk, A[i].data(), nk * sizeof(double));

    for (int k = 0; k < nk; ++k)
        std::memcpy(b + k * nj, B[k].data(), nj * sizeof(double));

    for (int i = 0; i < ni; ++i)
        std::memcpy(c + i * nj, C[i].data(), nj * sizeof(double));

    // parallel outer loop
    #pragma omp parallel for schedule(static)
    for (int ii = 0; ii < ni; ii += BLOCK_I) {
        int i_end = std::min(ii + BLOCK_I, ni);
        for (int jj = 0; jj < nj; jj += BLOCK_J) {
            int j_end = std::min(jj + BLOCK_J, nj);
            for (int kk = 0; kk < nk; kk += BLOCK_K) {
                int k_end = std::min(kk + BLOCK_K, nk);

                for (int i = ii; i < i_end; ++i) {
                    double *c_i   = c + i * nj;
                    double *a_i   = a + i * nk;
                    for (int k = kk; k < k_end; ++k) {
                        double aik = alpha * a_i[k];
                        double *b_k = b + k * nj;
                        for (int j = jj; j < j_end; ++j)
                            c_i[j] += aik * b_k[j];
                    }
                }
            }
        }
    }

    // Scale C by beta (can be fused with the accumulation)
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < ni; ++i) {
        double *c_i = c + i * nj;
        for (int j = 0; j < nj; ++j)
            c_i[j] = beta * c_i[j] + c_i[j];
    }

    // Copy back to the 2‑D containers
    for (int i = 0; i < ni; ++i)
        std::memcpy(C[i].data(), c + i * nj, nj * sizeof(double));

    delete[] a;
    delete[] b;
    delete[] c;
}
