                 std::vector<double>& r) {
    /* Initialise output vectors */
    std::fill(s.begin(), s.end(), 0.0);
    std::fill(q.begin(), q.end(), 0.0);

    /* Determine the number of threads to use */
    const int nthreads = omp_get_max_threads();

    /* Each thread keeps its own local copy of s to avoid atomic
       updates. After the parallel loop we reduce them into the final
       result. */
    std::vector<std::vector<double>> s_local(nthreads,
                                            std::vector<double>(m, 0.0));

#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::vector<double>& s_tmp = s_local[tid];

#pragma omp for schedule(static)
        for (int i = 0; i < n; ++i) {
            /* local accumulators for this row */
            for (int j = 0; j < m; ++j) {
                s_tmp[j] += r[i] * A[i][j];
                q[i] += A[i][j] + p[j];
            }
        }

        /* Merge thread‐local s contributions into the final s vector */
#pragma omp barrier
        for (int j = 0; j < m; ++j) {
            /* Reduction of the column j across threads */
            double sum = 0.0;
            for (int t = 0; t < nthreads; ++t)
                sum += s_local[t][j];
            s[j] += sum;
        }
    }
}
