/* QR Decomposition with Modified Gram Schmidt:
   http://www.inf.ethz.ch/personal/gander/ */
void kernel_gramschmidt(int m, int n,
                        std::vector<std::vector<double>>& A,
                        std::vector<std::vector<double>>& R,
                        std::vector<std::vector<double>>& Q) {
    // Use raw pointers for faster indexing
    double** a = new double*[m];
    double** r = new double*[n];
    double** q = new double*[m];
    for (int i = 0; i < m; ++i) a[i] = A[i].data();
    for (int i = 0; i < n; ++i) r[i] = R[i].data();
    for (int i = 0; i < m; ++i) q[i] = Q[i].data();

    for (int k = 0; k < n; ++k) {
        // 1. Compute norm of column k of A
        double nrm = 0.0;
#pragma omp parallel for reduction(+:nrm) schedule(static)
        for (int i = 0; i < m; ++i) {
            nrm += a[i][k] * a[i][k];
        }
        r[k][k] = std::sqrt(nrm);

        // 2. Normalize column k into Q
#pragma omp parallel for schedule(static)
        for (int i = 0; i < m; ++i) {
            q[i][k] = a[i][k] / r[k][k];
        }

        // 3. Orthogonalize remaining columns
        for (int j = k + 1; j < n; ++j) {
            // Compute R[k][j] = Q[:,k]^T * A[:,j]
            double rkj = 0.0;
#pragma omp parallel for reduction(+:rkj) schedule(static)
            for (int i = 0; i < m; ++i) {
                rkj += q[i][k] * a[i][j];
            }
            r[k][j] = rkj;

            // Subtract projection from A[:,j]
#pragma omp parallel for schedule(static)
            for (int i = 0; i < m; ++i) {
                a[i][j] -= q[i][k] * rkj;
            }
        }
    }

    delete[] a;
    delete[] r;
    delete[] q;
}
