/* Main computational kernel. The whole function will be timed,
   including the call and return. */
void kernel_ludcmp(int n,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& b,
                   std::vector<double>& x,
                   std::vector<double>& y)
{
    // LU factorisation with partial pivoting omitted (exact behaviour)
    for (int i = 0; i < n; ++i)
    {
        double* row_i = A[i].data();

        // Lower part, j < i
        for (int j = 0; j < i; ++j)
        {
            double w = row_i[j];
            const double* row_k = A[i].data();
            const double* row_kj = A[j].data();
            for (int k = 0; k < j; ++k)
                w -= row_k[k] * row_kj[k];
            row_i[j] = w / row_kj[j];
        }

        // Upper part, j >= i
        for (int j = i; j < n; ++j)
        {
            double w = row_i[j];
            for (int k = 0; k < i; ++k)
                w -= row_i[k] * A[k][j];
            row_i[j] = w;
        }
    }

    // Forward substitution Ly = b
    for (int i = 0; i < n; ++i)
    {
        double w = b[i];
        for (int j = 0; j < i; ++j)
            w -= A[i][j] * y[j];
        y[i] = w;
    }

    // Backward substitution Ux = y
    for (int i = n - 1; i >= 0; --i)
    {
        double w = y[i];
        for (int j = i + 1; j < n; ++j)
            w -= A[i][j] * x[j];
        x[i] = w / A[i][i];
    }
}
