/* -------------------------------------------------------------------- *
 *  Faster GEMVER kernel.  All non‑trivial work is performed with         *
 *  contiguous row‑major access on a raw pointer derived from         *
 *  A[i][j] to maximise cache locality and vectorisation.          *
 *  -------------------------------------------------------------- */
void kernel_gemver(int n,
                   double alpha,
                   double beta,
                   std::vector<std::vector<double>>& A,
                   std::vector<double>& u1,
                   std::vector<double>& v1,
                   std::vector<double>& u2,
                   std::vector<double>& v2,
                   std::vector<double>& w,
                   std::vector<double>& x,
                   std::vector<double>& y,
                   std::vector<double>& z)
{
    /* Assume A is stored row‑major and contiguous.  Create a raw pointer     */
    /* that references the first element of the underlying storage.  This    */
    /* way we can do uninhibited pointer arithmetic and let the compiler      */
    /* generate efficient SIMD code.                                           */
    double* const a = &A[0][0];

    /* 1st step : A += u1*v1^T + u2*v2^T */
    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i) {
        const double ui1 = u1[i];
        const double ui2 = u2[i];
        double* const row = a + i * n;
        for (int j = 0; j < n; ++j) {
            row[j] += ui1 * v1[j] + ui2 * v2[j];
        }
    }

    /* 2nd step : x += beta * A^T * y   (column‑wise dot products)          */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        for (int j = 0; j < n; ++j) {
            sum += a[j * n + i] * y[j];        // A[j][i] in row‑major
        }
        x[i] += beta * sum;
    }

    /* 3rd step : x += z   */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        x[i] += z[i];
    }

    /* 4th step : w += alpha * A * x   (vector–matrix product)              */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; ++i) {
        double sum = 0.0;
        const double* const row = a + i * n;
        for (int j = 0; j < n; ++j) {
            sum += row[j] * x[j];
        }
        w[i] += alpha * sum;
    }
}
