/* Helper to compute the linear index for (i,j) in a flattened 2‑D array */
inline std::size_t idx(std::size_t i, std::size_t j, std::size_t n)
{
    return i * n + j;
}

/* Main computational kernel.  The whole function will be timed,
   including the call and return. */
void kernel_seidel_2d(int tsteps,
		      int n,
		      std::vector<std::vector<double>>& A)
{
    /* Flatten the 2‑D vector to improve cache locality */
    std::vector<double> flat(n * n);
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            flat[idx(i, j, n)] = A[i][j];

    const double inv9 = 1.0 / 9.0;

    for (int t = 0; t < tsteps; ++t) {
        /* The loop order is kept as in the original to preserve the
           in‑place Seidel update order. */
        for (int i = 1; i <= n - 2; ++i) {
            std::size_t base = idx(i, 0, n);
            std::size_t prev = idx(i - 1, 0, n);
            std::size_t next = idx(i + 1, 0, n);

            for (int j = 1; j <= n - 2; ++j) {
                double sum =
                      flat[prev + j - 1] + flat[prev + j] + flat[prev + j + 1]
                    + flat[base + j - 1] + flat[base + j] + flat[base + j + 1]
                    + flat[next + j - 1] + flat[next + j] + flat[next + j + 1];
                flat[base + j] = sum * inv9;
            }
        }
    }

    /* Copy the flattened result back into the original 2‑D vector */
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            A[i][j] = flat[idx(i, j, n)];
}
