/* Main computational kernel. The whole function will be timed,
   including the call and return. */
/*
  Original version by Dave Wonnacott at Haverford College <davew@cs.haverford.edu>,
  with help from Allison Lake, Ting Zhou, and Tian Jin,
  based on algorithm by Nussinov, described in Allison Lake's senior thesis.
*/

void kernel_nussinov(int n, std::vector<int>& seq,
		     std::vector<std::vector<int>>& table) {
    // Helper inline match function
    auto match = [](int b1, int b2) -> int {
        return (b1 + b2 == 3) ? 1 : 0;
    };

    int* seq_data = seq.data();          // raw pointer for faster indexing
    std::vector<int*> row_ptr(n);        // pointers to each row of table
    for (int i = 0; i < n; ++i)
        row_ptr[i] = table[i].data();

    /* Process diagonals by increasing length.
       This allows parallelization of the outer i loop (diagonal elements)             */
    for (int len = 1; len < n; ++len) {
        #pragma omp parallel for schedule(static)
        for (int i = 0; i + len < n; ++i) {
            int j = i + len;
            int* row_i = row_ptr[i];
            int* row_i1 = (i + 1 < n) ? row_ptr[i + 1] : nullptr;
            int* row_k = nullptr;
            int best = row_i[j];           // initially whatever is there (zero)

            // table[i][j-1] and table[i+1][j]
            if (j - 1 >= 0)
                best = std::max(best, row_i[j - 1]);
            if (row_i1 != nullptr)
                best = std::max(best, row_i1[j]);

            // table[i+1][j-1] + match
            if (row_i1 != nullptr && j - 1 >= 0) {
                int val = row_i1[j - 1] + match(seq_data[i], seq_data[j]);
                best = std::max(best, val);
            }

            // split at k
            for (int k = i + 1; k < j; ++k) {
                int val = row_ptr[i][k] + row_ptr[k + 1][j];
                if (val > best)
                    best = val;
            }

            row_i[j] = best;
        }
    }
}
