       independent.  The inner loops are kept sequential for
       cache locality.  Each thread works on disjoint rows of C. */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < m; ++i) {
        double *c_row = C[i].data();        // C[i][*]
        double *a_row = A[i].data();        // A[i][*]
        double *b_row = B[i].data();        // B[i][*]

        const double a_ii = a_row[i];       // A[i][i]
        for (int j = 0; j < n; ++j) {
            double temp = 0.0;
            const double b_ij = b_row[j];

            /* Accumulate the lower‑triangular contribution first.
               We keep the access to B[k][j] inside the innermost loop.
               The outer loop over i is still parallel.          */
            for (int k = 0; k < i; ++k) {
                double a_ik = a_row[k];
                const double b_kj = B[k][j];
                c_row[j] += a * b_ij * a_ik;   // C[k][j] += alpha * B[i][j] * A[i][k]
