void kernel_heat_3d(int tsteps,
                    int n,
                    std::vector<std::vector<std::vector<double>>>& A,
                    std::vector<std::vector<std::vector<double>>>& B)
{
    /* Flatten the 3‑D vectors into 1‑D buffers for cache efficiency. */
    const std::size_t N = static_cast<std::size_t>(n) * n * n;
    std::vector<double> a(N), b(N);

    /* Copy original data into flattened buffers. */
    #pragma omp parallel for collapse(3)
    for (int i = 0; i < n; ++i)
        for (int j = 0; j < n; ++j)
            for (int k = 0; k < n; ++k)
                a[idx(i,j,k,n)] = A[i][j][k];

    const double coef = 0.125;

    for (int t = 1; t <= tsteps; ++t) {
        /* Update B from A */
        #pragma omp parallel for collapse(3) schedule(static)
        for (int i = 1; i < n - 1; ++i)
            for (int j = 1; j < n - 1; ++j)
                for (int k = 1; k < n - 1; ++k) {
                    std::size_t id = idx(i,j,k,n);
                    double a_ip = a[idx(i+1,j,k,n)];
                    double a_im = a[idx(i-1,j,k,n)];
                    double a_jp = a[idx(i,j+1,k,n)];
                    double a_jm = a[idx(i,j-1,k,n)];
                    double a_kp = a[idx(i,j,k+1,n)];
                    double a_km = a[idx(i,j,k-1,n)];
