/* Reimplementation of the Jacobi kernel that is
 * cache‑friendly, vectorised by the compiler and
 * fully parallelised with OpenMP.  The external
 * API (signature) is preserved so that the harness
 * remains unchanged.
 */

void kernel_jacobi_2d(int tsteps,
                      int n,
                      std::vector<std::vector<double>>& A,
                      std::vector<std::vector<double>>& B)
{
    // Pointers to the underlying contiguous blocks
    // of the 2D vectors so indexes can be
    // translated into simple pointer arithmetic.
    const std::size_t stride = static_cast<std::size_t>(n);
    double *a = &A[0][0];
    double *b = &B[0][0];

    // Anti‑aliasing hints for the compiler
    const double coef = 0.2;

    for (int t = 0; t < tsteps; ++t)
    {
        // ---- First half: compute B from A  ----
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < n-1; ++i)
        {
            double *row   = a + i*stride;     // A[i][]
            double *row_p = a + (i-1)*stride; // A[i-1][]
            double *row_n = a + (i+1)*stride; // A[i+1][]
            double *c     = b + i*stride;     // B[i][]
            for (int j = 1; j < n-1; ++j)
            {
                // A[i][j]  = row[j]
                // A[i][j-1] = row[j-1]
                // A[i][j+1] = row[j+1]
                // A[i-1][j] = row_p[j]
                // A[i+1][j] = row_n[j]
                c[j] = coef * (row[j] + row[j-1] + row[j+1] +
                               row_p[j] + row_n[j]);
            }
        }

        // ---- Second half: compute A from B  ----
        #pragma omp parallel for collapse(2) schedule(static)
        for (int i = 1; i < n-1; ++i)
        {
            double *row   = b + i*stride;     // B[i][]
            double *row_p = b + (i-1)*stride; // B[i-1][]
            double *row_n = b + (i+1)*stride; // B[i+1][]
            double *c     = a + i*stride;     // A[i][]
            for (int j = 1; j < n-1; ++j)
            {
                // B[i][j]  = row[j]
                // B[i][j-1] = row[j-1]
                // B[i][j+1] = row[j+1]
                // B[i-1][j] = row_p[j]
                // B[i+1][j] = row_n[j]
                c[j] = coef * (row[j] + row[j-1] + row[j+1] +
                               row_p[j] + row_n[j]);
            }
        }
    }
