void kernel_atax(int m, int n,
                 std::vector<std::vector<double>>& A,
                 std::vector<double>& x,
                 std::vector<double>& y,
                 std::vector<double>& tmp) {
    // zero initial y (can be done once before the loop)
    #pragma omp parallel for
    for (int j = 0; j < n; ++j) y[j] = 0.0;

    // each thread accumulates its own partial y contribution
    int num_threads = 1;
    #pragma omp parallel
    {
        num_threads = omp_get_num_threads();
    }
    std::vector<std::vector<double>> y_local(num_threads, std::vector<double>(n, 0.0));

    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        #pragma omp for
        for (int i = 0; i < m; ++i) {
            double sum = 0.0;
            for (int j = 0; j < n; ++j) sum += A[i][j] * x[j];
            tmp[i] = sum;
            for (int j = 0; j < n; ++j) y_local[tid][j] += A[i][j] * sum;
        }
    }

    // merge partial results into y
    #pragma omp parallel for
    for (int j = 0; j < n; ++j) {
        double acc = 0.0;
        for (int t = 0; t < num_threads; ++t) acc += y_local[t][j];
        y[j] = acc;
    }
}
