    const double DY = 1.0 / n;
    const double DT = 1.0 / tsteps;
    const double B1 = 2.0;
    const double B2 = 1.0;

    const double mul1 = B1 * DT / (DX * DX);
    const double mul2 = B2 * DT / (DY * DY);

    const double a = -mul1 * 0.5;
    const double b = 1.0 + mul1;
    const double c = a;
    const double d = -mul2 * 0.5;
    const double e = 1.0 + mul2;
    const double f = d;

    /* pre‑allocate raw pointers for faster access */
    std::vector<double*> up(n), vp(n), pp(n), qp(n);

    for (int t = 1; t <= tsteps; ++t) {
        /* ----------------------------------------------------------
           forward sweep in the v‑direction (1st set of nested loops)
           ---------------------------------------------------------- */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            double* vu      = v[i].data();
            double* pu      = p[i].data();
            double* qu      = q[i].data();

            /* initialise first column */
            vu[0] = 1.0;
            pu[0] = 0.0;
            qu[0] = vu[0];

            /* forward pass over j */
            for (int j = 1; j < n - 1; ++j) {
                const double denom = a * pu[j-1] + b;
                pu[j] = -c / denom;
                qu[j] = (-d * u[j][i - 1] +
                         (1.0 + 2.0 * d) * u[j][i] -
                         f * u[j][i + 1] -
                         a * qu[j-1]) / denom;
            }

            /* last column */
            vu[n-1] = 1.0;

            /* backward pass over j */
            for (int j = n - 2; j >= 1; --j) {
                vu[j] = pu[j] * vu[j + 1] + qu[j];
            }
        }

        /* ----------------------------------------------------------
           forward sweep in the u‑direction (2nd set of nested loops)
           ---------------------------------------------------------- */
#pragma omp parallel for schedule(static)
        for (int i = 1; i < n - 1; ++i) {
            double* uu      = u[i].data();
            double* pu      = p[i].data();
            double* qu      = q[i].data();

            /* initialise first column */
            uu[0] = 1.0;
            pu[0] = 0.0;
            qu[0] = uu[0];

            /* forward pass over j */
            for (int j = 1; j < n - 1; ++j) {
                const double denom = d * pu[j-1] + e;
                pu[j] = -f / denom;
                qu[j] = (-a * v[i-1][j] +
                         (1.0 + 2.0 * a) * v[i][j] -
                         c * v[i+1][j] -
                         d * qu[j-1]) / denom;
            }

            /* last column */
            uu[n-1] = 1.0;

            /* backward pass over j */
            for (int j = n - 2; j >= 1; --j) {
                uu[j] = pu[j] * uu[j + 1] + qu[j];
            }
        }
    }
