#include <cmath>
#include <vector>
#include <thread>
#include <omp.h>

/* ------------------------------------------------------------------
 * Optimised Deriche filter kernel.
 * ------------------------------------------------------------------
 * The implementation keeps identical external behaviour but
 * replaces the double‑nested std::vector access with flat, cache‑friendly
 * 1‑D arrays.  All the heavy work is parallelised with OpenMP.
 * ------------------------------------------------------------------ */

static inline float exp_neg_alpha(float alpha) {
    return std::exp(-alpha);
}

void kernel_deriche(int w, int h, double alpha,
                    std::vector<std::vector<float>>& imgIn,
                    std::vector<std::vector<float>>& imgOut,
                    std::vector<std::vector<float>>& y1,
                    std::vector<std::vector<float>>& y2)
{
    /* ---------- 1‑D representation ---------------------------------- */
    const size_t N = static_cast<size_t>(w) * h;
    std::vector<float> flatIn(N), flatOut(N), flatY1(N), flatY2(N);

    // Flatten the input
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            flatIn[i*h + j] = imgIn[i][j];

    /* ---------- coefficients -------------------------------------- */
    const float exp_alpha = exp_neg_alpha(alpha);
    const float exp_2alpha = exp_alpha * exp_alpha;
    const float denom = 1.0f + 2.0f*static_cast<float>(alpha)*exp_alpha - exp_2alpha;
    const float k = 1.0f - exp_alpha*(1.0f - exp_alpha)/denom;

    const float a1 = k,             a2 = k*exp_alpha*(static_cast<float>(alpha)-1.0f),
                  a3 = k*exp_alpha*(static_cast<float>(alpha)+1.0f),
                  a4 = -k*exp_2alpha,
                  a5 = k,             a6 = k*exp_alpha*(static_cast<float>(alpha)-1.0f),
                  a7 = k*exp_alpha*(static_cast<float>(alpha)+1.0f),
                  a8 = -k*exp_2alpha;

    const float b1 = static_cast<float>(std::pow(2.0, -alpha));
    const float b2 = -exp_2alpha;
    const float c1 = 1.0f, c2 = 1.0f;

    /* ---------- forward horizontal ------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float ym1 = 0.0f, ym2 = 0.0f, xm1 = 0.0f;
        size_t off = i * h;
        for (int j = 0; j < h; ++j) {
            const float xj = flatIn[off + j];
            const float y = a1*xj + a2*xm1 + b1*ym1 + b2*ym2;
            flatY1[off + j] = y;
            xm1 = xj;       ym2 = ym1;   ym1 = y;
        }
    }

    /* ---------- backward horizontal ------------------------------ */
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < w; ++i) {
        float yp1 = 0.0f, yp2 = 0.0f, xp1 = 0.0f, xp2 = 0.0f;
        size_t off = i * h;
        for (int j = h-1; j >= 0; --j) {
            const float xj = flatIn[off + j];
            const float y = a3*xp1 + a4*xp2 + b1*yp1 + b2*yp2;
            flatY2[off + j] = y;
            xp2 = xp1;   xp1 = xj;   yp2 = yp1;   yp1 = y;
        }
    }

    /* ---------- add horizontal contributions -------------------- */
    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < N; ++idx)
        flatOut[idx] = c1 * (flatY1[idx] + flatY2[idx]);

    /* ---------- forward vertical --------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tm1 = 0.0f, ym1 = 0.0f, ym2 = 0.0f;
        for (int i = 0; i < w; ++i) {
            const float yj = flatOut[i*h + j];
            const float y = a5*yj + a6*tm1 + b1*ym1 + b2*ym2;
            flatY1[i*h + j] = y;
            tm1 = yj;   ym2 = ym1;   ym1 = y;
        }
    }

    /* ---------- backward vertical -------------------------------- */
    #pragma omp parallel for schedule(static)
    for (int j = 0; j < h; ++j) {
        float tp1 = 0.0f, tp2 = 0.0f, yp1 = 0.0f, yp2 = 0.0f;
        for (int i = w-1; i >= 0; --i) {
            const float yj = flatOut[i*h + j];
            const float y = a7*tp1 + a8*tp2 + b1*yp1 + b2*yp2;
            flatY2[i*h + j] = y;
            tp2 = tp1;   tp1 = yj;   yp2 = yp1;   yp1 = y;
        }
    }

    /* ---------- final addition ----------------------------------- */
    #pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < N; ++idx)
        flatOut[idx] = c2 * (flatY1[idx] + flatY2[idx]);

    /* ---------- copy back to the 2‑D vectors -------------------- */
    for (int i = 0; i < w; ++i)
        for (int j = 0; j < h; ++j)
            imgOut[i][j] = flatOut[i*h + j];
}
